# Unit Tests for `interleave`

```python
import pytest


def interleave(a: list, b: list) -> list:
    result = []
    for x, y in zip(a, b):
        result.extend([x, y])
    result.extend(a[len(b):] or b[len(a):])
    return result


class TestInterleaveHappyPath:
    """Tests for typical, expected use cases."""

    def test_equal_length_lists(self):
        assert interleave([1, 2, 3], ['a', 'b', 'c']) == [1, 'a', 2, 'b', 3, 'c']

    def test_two_element_lists(self):
        assert interleave([1, 2], [3, 4]) == [1, 3, 2, 4]

    def test_single_element_lists(self):
        assert interleave([1], ['x']) == [1, 'x']

    def test_strings_as_elements(self):
        assert interleave(['hello', 'world'], ['foo', 'bar']) == ['hello', 'foo', 'world', 'bar']


class TestInterleaveDifferentLengths:
    """Tests for lists of unequal length."""

    def test_a_longer_than_b(self):
        assert interleave([1, 2, 3, 4, 5], ['a', 'b']) == [1, 'a', 2, 'b', 3, 4, 5]

    def test_b_longer_than_a(self):
        assert interleave([1, 2], ['a', 'b', 'c', 'd']) == [1, 'a', 2, 'b', 'c', 'd']

    def test_a_one_element_b_many(self):
        assert interleave([1], ['a', 'b', 'c']) == [1, 'a', 'b', 'c']

    def test_a_many_b_one_element(self):
        assert interleave([1, 2, 3], ['a']) == [1, 'a', 2, 3]


class TestInterleaveEdgeCases:
    """Edge cases including empty lists and special values."""

    def test_both_empty(self):
        assert interleave([], []) == []

    def test_a_empty_b_not(self):
        assert interleave([], [1, 2, 3]) == [1, 2, 3]

    def test_b_empty_a_not(self):
        assert interleave([1, 2, 3], []) == [1, 2, 3]

    def test_with_none_values(self):
        assert interleave([None, None], [1, 2]) == [None, 1, None, 2]

    def test_with_nested_lists(self):
        assert interleave([[1, 2], [3, 4]], [[5], [6]]) == [[1, 2], [5], [3, 4], [6]]

    def test_with_mixed_types(self):
        assert interleave([1, 'two', 3.0], [True, None, {'a': 1}]) == [
            1, True, 'two', None, 3.0, {'a': 1}
        ]

    def test_does_not_mutate_inputs(self):
        a = [1, 2, 3]
        b = ['a', 'b']
        a_copy, b_copy = a.copy(), b.copy()
        interleave(a, b)
        assert a == a_copy
        assert b == b_copy

    def test_returns_new_list(self):
        a = [1, 2]
        b = [3, 4]
        result = interleave(a, b)
        assert result is not a
        assert result is not b


class TestInterleaveFalsyTailQuirk:
    """
    Tests exposing the `or` short-circuit bug:
    when the leftover slice from `a` is falsy (e.g., contains only falsy
    items? no — actually only when the *list itself* is empty),
    the function falls back to `b[len(a):]`.

    Because the leftover slice is empty exactly when `len(a) <= len(b)`,
    the `or` works correctly in normal cases. However, if both leftover
    slices are non-empty it would be a bug — this can't happen here.
    But we can still verify behavior with empty leftovers explicitly.
    """

    def test_a_leftover_empty_falls_back_to_b(self):
        # len(a) == len(b), both leftovers empty, result tail empty
        assert interleave([1], [2]) == [1, 2]

    def test_falsy_elements_in_tail_preserved(self):
        # Tail contains falsy values but is a non-empty list, so `or` is fine
        assert interleave([0, 0, 0, 0], [1, 2]) == [0, 1, 0, 2, 0, 0]

    def test_falsy_tail_in_b(self):
        assert interleave([1, 2], [0, 0, 0, 0]) == [1, 0, 2, 0, 0, 0]


class TestInterleaveErrorCases:
    """Tests for invalid inputs."""

    def test_none_as_first_arg_raises(self):
        with pytest.raises(TypeError):
            interleave(None, [1, 2, 3])

    def test_none_as_second_arg_raises(self):
        with pytest.raises(TypeError):
            interleave([1, 2, 3], None)

    def test_int_as_arg_raises(self):
        with pytest.raises(TypeError):
            interleave(123, [1, 2])

    def test_works_with_tuples_via_duck_typing(self):
        # zip works with tuples, but slicing differs; tuples support slicing too.
        # The function is annotated for lists but duck-types fine here.
        result = interleave((1, 2, 3), ('a', 'b'))
        assert result == [1, 'a', 2, 'b', 3]


